const State = enum(u8) {
    idle,
    one_a,
    circumflex,
    literal,
};

pub const ProcessKeyEventResult = extern struct {
    num_backspaces: u8,
    num_chars: u8,
    swallow_event: bool,
    chars: [*]const u16,
};

var state: State = .idle;
var first_a_upper: bool = false;
var gap: u8 = 0;

var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
var active: u1 = 0;

fn writeBuf() [*]u16 {
    return @ptrCast(&bufs[active]);
}

fn flip() void {
    active ^= 1;
}

fn passthrough() ProcessKeyEventResult {
    return .{
        .num_backspaces = 0,
        .num_chars = 0,
        .swallow_event = false,
        .chars = @ptrCast(&bufs[0]),
    };
}

fn isA(c: u16) bool {
    return c == 0x0061 or c == 0x0041;
}

fn isUpperA(c: u16) bool {
    return c == 0x0041;
}

fn isAlphanumeric(c: u16) bool {
    return (c >= 0x0030 and c <= 0x0039) or
        (c >= 0x0041 and c <= 0x005A) or
        (c >= 0x0061 and c <= 0x007A);
}

export fn reset_state() void {
    state = .idle;
    first_a_upper = false;
    gap = 0;
}

export fn process_backspace() ProcessKeyEventResult {
    if (gap > 0) {
        gap -= 1;
    } else if (state != .idle) {
        reset_state();
    }
    return passthrough();
}

export fn process_key_event(char_code: u16) ProcessKeyEventResult {
    if (isA(char_code)) {
        if (gap == 0) {
            return handleA(char_code);
        }
        if (gap >= 255) {
            reset_state();
            return passthrough();
        }
        gap += 1;
        return passthrough();
    }
    if (isAlphanumeric(char_code)) {
        if (state != .idle) {
            if (gap >= 255) {
                reset_state();
                return passthrough();
            }
            gap += 1;
        }
        return passthrough();
    }
    reset_state();
    return passthrough();
}

fn handleA(char_code: u16) ProcessKeyEventResult {
    const upper = isUpperA(char_code);
    switch (state) {
        .idle => {
            state = .one_a;
            first_a_upper = upper;
            return passthrough();
        },
        .one_a => {
            state = .circumflex;
            const buf = writeBuf();
            buf[0] = if (first_a_upper) 0x00C2 else 0x00E2;
            flip();
            return .{
                .num_backspaces = 1,
                .num_chars = 1,
                .swallow_event = true,
                .chars = buf,
            };
        },
        .circumflex => {
            state = .literal;
            const buf = writeBuf();
            buf[0] = if (first_a_upper) 0x0041 else 0x0061;
            buf[1] = if (upper) 0x0041 else 0x0061;
            flip();
            return .{
                .num_backspaces = 1,
                .num_chars = 2,
                .swallow_event = true,
                .chars = buf,
            };
        },
        .literal => {
            return passthrough();
        },
    }
}

